import { GRID, COLORS } from '../../game/GameConfig.js';
import { spectaclesTransformString, isSpectaclesActive } from '../../data/cipher.js';

/**
 * NeutralRenderer - Renders NEUTRAL state (Leshy Grove, future shops/puzzles)
 * Similar to ExploreRenderer but simplified (no enemies, combat, etc.)
 * Scripts can optionally provide onRender hook for custom overlays
 */
export class NeutralRenderer {
  constructor(renderer, renderController) {
    this.renderer = renderer;
    this.renderController = renderController;
  }

  render(game) {
    if (!game.currentRoom || !game.player) return;

    this.renderBackground(game);
    this.renderForeground(game);
  }

  renderBackground(game) {
    // Render background (only if dirty)
    if (!this.renderer.backgroundDirty) return;

    this.renderer.clearBackground('#000000');

    // Draw border with exits (neutral rooms always have exits unlocked)
    this.renderer.drawBorder(game.currentRoom.exits, game.currentRoom.borderColor || '#00ff00');

    // Draw static background objects (grass on background layer)
    for (const obj of game.currentRoom.backgroundObjects) {
      if (!obj.destroyed && !obj.currentAnimation) {
        const x = obj.position.x + GRID.CELL_SIZE / 2 + (obj.renderOffsetX || 0);
        const y = obj.position.y + GRID.CELL_SIZE / 2 + (obj.renderOffsetY || 0);
        this.renderer.bgCtx.fillStyle = obj.color;
        this.renderer.bgCtx.fillText(obj.char, x, y);
      }
    }

    this.renderer.backgroundDirty = false;
  }

  renderForeground(game) {
    this.renderer.clearForeground();

    const centerX = Math.floor(GRID.COLS / 2);
    const centerY = Math.floor(GRID.ROWS / 2);

    // Draw return-exit warp zone on the entry edge (south / west / east)
    const returnExit = game.currentRoom.returnExit || 'south';
    if (game.currentRoom.exits[returnExit]) {
      const warpZoneColor = 'rgba(100, 150, 255, 0.15)';
      if (returnExit === 'south') {
        this.renderer.drawRect(
          (centerX - 1) * GRID.CELL_SIZE,
          (GRID.ROWS - 3) * GRID.CELL_SIZE,
          3 * GRID.CELL_SIZE,
          2 * GRID.CELL_SIZE,
          warpZoneColor,
          true
        );
      } else if (returnExit === 'west') {
        this.renderer.drawRect(
          1 * GRID.CELL_SIZE,
          (centerY - 1) * GRID.CELL_SIZE,
          2 * GRID.CELL_SIZE,
          3 * GRID.CELL_SIZE,
          warpZoneColor,
          true
        );
      } else if (returnExit === 'east') {
        this.renderer.drawRect(
          (GRID.COLS - 3) * GRID.CELL_SIZE,
          (centerY - 1) * GRID.CELL_SIZE,
          2 * GRID.CELL_SIZE,
          3 * GRID.CELL_SIZE,
          warpZoneColor,
          true
        );
      }
    }

    // Draw animating background objects
    for (const obj of game.currentRoom.backgroundObjects) {
      if (obj.currentAnimation) {
        const renderData = obj.getRenderPosition();
        this.renderer.drawEntity(
          renderData.x + GRID.CELL_SIZE / 2 + obj.animationOffset.x + (obj.renderOffsetX || 0),
          renderData.y + GRID.CELL_SIZE / 2 + obj.animationOffset.y + (obj.renderOffsetY || 0),
          renderData.char,
          renderData.color
        );
      }
    }

    // Draw items (prizes)
    for (const item of game.items) {
      const x = item.position.x + GRID.CELL_SIZE / 2;
      const y = item.position.y + GRID.CELL_SIZE / 2;
      this.renderer.drawEntity(x, y, item.char, item.color);
    }

    // Draw ingredients (Leshy grass prize drops live in the ingredients array)
    for (const ingredient of game.ingredients) {
      const x = ingredient.position.x + GRID.CELL_SIZE / 2;
      const y = ingredient.position.y + GRID.CELL_SIZE / 2;
      this.renderer.drawEntity(x, y, ingredient.char, ingredient.color);
    }

    // Draw neutral characters (Leshy, Fairy, etc.)
    for (const neutralChar of game.neutralCharacters) {
      neutralChar.render(this.renderer.fgCtx, (gx, gy) => ({
        x: gx * GRID.CELL_SIZE,
        y: gy * GRID.CELL_SIZE
      }));
    }

    // Script-specific rendering before player (background-layer content e.g. draw canvas)
    if (game.neutralRoomSystem.currentScript?.onRenderBefore) {
      game.neutralRoomSystem.currentScript.onRenderBefore(
        this.renderer, game.currentRoom, game.player, game.neutralRoomSystem.state
      );
    }

    // Draw player
    const pulseAlpha = game.player.getPulseAlpha ? game.player.getPulseAlpha() : 1.0;
    this.renderer.drawTextWithAlpha(
      game.player.position.x + GRID.CELL_SIZE / 2,
      game.player.position.y + GRID.CELL_SIZE / 2,
      game.player.char,
      game.player.color,
      pulseAlpha
    );

    // Follower flock (persists across rooms after feeding events).
    if (game.followerCrows && game.followerCrows.length > 0) {
      for (const f of game.followerCrows) {
        const fOff = f.getRenderOffsetY();
        this.renderer.drawEntity(
          f.position.x + GRID.CELL_SIZE / 2,
          f.position.y + GRID.CELL_SIZE / 2 + fOff,
          f.char,
          f.color
        );
      }
    }

    // Companion crows: persist across states; perch around the player.
    if (game.companionCrows && game.companionCrows.length > 0) {
      for (const c of game.companionCrows) {
        const offY = c.getRenderOffsetY();
        this.renderer.drawEntity(
          c.position.x + GRID.CELL_SIZE / 2,
          c.position.y + GRID.CELL_SIZE / 2 + offY,
          c.char,
          c.color
        );
      }
    }

    // Script-specific rendering (if script provides onRender hook)
    if (game.neutralRoomSystem.currentScript && game.neutralRoomSystem.currentScript.onRender) {
      game.neutralRoomSystem.currentScript.onRender(
        this.renderer,
        game.currentRoom,
        game.player,
        game.neutralRoomSystem.state
      );
    }

    // Draw cuts-remaining counter while minigame is active
    const nrState = game.neutralRoomSystem.state;
    if (nrState && nrState.cutsRemaining !== undefined && !nrState.celebrationActive) {
      const ctx = this.renderer.fgCtx;
      ctx.save();
      ctx.font = `${GRID.CELL_SIZE}px 'Unifont', monospace`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'top';
      ctx.fillStyle = '#00cc44';
      ctx.globalAlpha = 0.85;
      const label = nrState.cutsRemaining > 0
        ? `[ choose ${nrState.cutsRemaining} ]`
        : `[ done ]`;
      ctx.fillText(spectaclesTransformString(label, isSpectaclesActive(game)), GRID.WIDTH / 2, GRID.CELL_SIZE * 1.5);
      ctx.restore();
    }

    // Draw pickup message (identical to EXPLORE/REST states)
    if (game.pickupMessage && game.pickupMessageTimer > 0) {
      const ctx = this.renderer.fgCtx;
      ctx.save();
      ctx.font = `${GRID.CELL_SIZE * 2}px 'Unifont', monospace`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = COLORS.ITEM;
      this.renderer.drawWrappedText(ctx, spectaclesTransformString(game.pickupMessage, isSpectaclesActive(game)), GRID.WIDTH / 2, GRID.HEIGHT / 2, GRID.WIDTH * 0.8, GRID.CELL_SIZE * 2.5);
      ctx.restore();
    }

    // Draw inventory overlay (if player is holding 'i')
    if (game.showInventory) {
      this.renderController.inventoryOverlay.render(game);
    }
  }
}
